const testData = [
  {
    publish_date: '2025-01-13',
    platform: 'instagram',
    content_type: 'post',
    title: 'Community Workshop Reminder',
    content: 'Join us tomorrow for our cooperative ownership workshop! 🌟',
    status: 'approved'
  },
  {
    publish_date: '2025-01-14',
    platform: 'facebook',
    content_type: 'post', 
    title: 'Future Event',
    content: 'This should be filtered out',
    status: 'approved'
  }
];

// Filter for today's content
const today = new Date().toISOString().split('T')[0];
const todaysContent = testData.filter(item => 
  item.publish_date === today && item.status === 'approved'
);

console.log('Today is:', today);
console.log('Filtered content:', todaysContent);

return todaysContent.map(item => ({ json: item }));

